MERGE INTO PCINTEGRAECOMMERCE_LAYOUTC T
USING (SELECT 1 AS CODLAYOUT, 'iFood - Tabela de Preço' AS DESCRICAO FROM DUAL) S
ON (T.CODLAYOUT = S.CODLAYOUT)
WHEN MATCHED THEN UPDATE SET T.DESCRICAO = S.DESCRICAO
WHEN NOT MATCHED THEN INSERT (CODLAYOUT, DESCRICAO) VALUES (S.CODLAYOUT, S.DESCRICAO);

