ON (T.CODLAYOUT = S.CODLAYOUT AND T.TIPO = S.TIPO AND T.CAMPO = S.CAMPO)
WHEN MATCHED THEN UPDATE SET T.DESCRICAO = S.DESCRICAO, T.TIPOCAMPO = S.TIPOCAMPO, T.OBRIGATORIO = S.OBRIGATORIO, T.ORDEMEXIBICAO = S.ORDEMEXIBICAO, T.EDITAVEL = S.EDITAVEL, T.VISIVEL = S.VISIVEL
WHEN NOT MATCHED THEN INSERT (CODLAYOUT, TIPO, CAMPO, DESCRICAO, TIPOCAMPO, OBRIGATORIO, ORDEMEXIBICAO, EDITAVEL, VISIVEL) VALUES (S.CODLAYOUT, S.TIPO, S.CAMPO, S.DESCRICAO, S.TIPOCAMPO, S.OBRIGATORIO, S.ORDEMEXIBICAO, S.EDITAVEL, S.VISIVEL);

MERGE INTO PCINTEGRAECOMMERCE_LAYOUTI T
USING (SELECT 2 AS CODLAYOUT, 'CONFIGURACOES' AS TIPO, 'CONSIDERAESTOQUEPRODMASTER' AS CAMPO, 'Considerar o estoque do produto master no produto filho' AS DESCRICAO, 'VARCHAR2' AS TIPOCAMPO, 'N' AS OBRIGATORIO, 10 AS ORDEMEXIBICAO, 'S' AS EDITAVEL, 'S' AS VISIVEL FROM DUAL) S
ON (T.CODLAYOUT = S.CODLAYOUT AND T.TIPO = S.TIPO AND T.CAMPO = S.CAMPO)
WHEN MATCHED THEN UPDATE SET T.DESCRICAO = S.DESCRICAO, T.TIPOCAMPO = S.TIPOCAMPO, T.OBRIGATORIO = S.OBRIGATORIO, T.ORDEMEXIBICAO = S.ORDEMEXIBICAO, T.EDITAVEL = S.EDITAVEL, T.VISIVEL = S.VISIVEL
WHEN NOT MATCHED THEN INSERT (CODLAYOUT, TIPO, CAMPO, DESCRICAO, TIPOCAMPO, OBRIGATORIO, ORDEMEXIBICAO, EDITAVEL, VISIVEL) VALUES (S.CODLAYOUT, S.TIPO, S.CAMPO, S.DESCRICAO, S.TIPOCAMPO, S.OBRIGATORIO, S.ORDEMEXIBICAO, S.EDITAVEL, S.VISIVEL);

COMMIT;

END;